  1→import React, {useCallback, useMemo, useRef, useState} from 'react';
  2→import {
  3→  ActivityIndicator,
  4→  Alert,
  5→  Image,
  6→  Pressable,
  7→  ScrollView,
  8→  StyleSheet,
  9→  Text,
 10→  TextInput,
 11→  View,
 12→} from 'react-native';
 13→import {useMutation, useQuery} from '@tanstack/react-query';
 14→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 15→import {SafeAreaView} from 'react-native-safe-area-context';
 16→import {Avatar} from '../../components/Avatar';
 17→import {BadgeCheckIcon, RepostIcon, XIcon} from '../../components/icons';
 18→import {CommentThread, formatRelativeDate} from '../../components/Comments';
 19→import {ActionBar} from '../../components/PostCard/ActionBar';
 20→import {PrimaryButton} from '../../components/PrimaryButton';
 21→import {SkeletonLoader} from '../../components/SkeletonLoader';
 22→import {LexicalRenderer} from '../../lib/content/LexicalRenderer';
 23→import {RelatedPosts} from '../../components/Discovery/RelatedPosts';
 24→import {useAuth} from '../../features/auth/AuthProvider';
 25→import {useTheme} from '../../theme/ThemeProvider';
 26→import {useComments} from '../../hooks/useComments';
 27→import {fonts, typeScale} from '../../theme/typography';
 28→import {spacing, radii} from '../../theme/spacing';
 29→import {mobileApi} from '../../lib/api/mobileApi';
 30→import {socialApi} from '../../lib/api/socialApi';
 31→import {queryClient} from '../../lib/queryClient';
 32→import {extractPlainText} from '../../lib/utils/journalHelpers';
 33→import type {RootStackParamList} from '../../navigation/types';
 34→
 35→type Props = NativeStackScreenProps<RootStackParamList, 'PostDetail'>;
 36→
 37→const toCount = (value: unknown): number | null => {
 38→  const parsed = Number(value);
 39→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 40→};
 41→
 42→const resolveCount = (
 43→  aggregate: Array<{count?: number}> | undefined,
 44→  fallback?: number,
 45→): number => {
 46→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 47→};
 48→
 49→const extractBannerImage = (content: string | null | undefined): string | null => {
 50→  if (!content) return null;
 51→  try {
 52→    const parsed = JSON.parse(content);
 53→    const findImage = (node: any): string | null => {
 54→      if (node.type === 'image' && node.src) return node.src;
 55→      if (node.children) {
 56→        for (const child of node.children) {
 57→          const found = findImage(child);
 58→          if (found) return found;
 59→        }
 60→      }
 61→      return null;
 62→    };
 63→    return findImage(parsed.root ?? parsed);
 64→  } catch {
 65→    return null;
 66→  }
 67→};
 68→
 69→export function PostDetailScreen({route, navigation}: Props) {
 70→  const {user, session} = useAuth();
 71→  const {colors} = useTheme();
 72→  const {journalId} = route.params;
 73→  const token = session?.access_token ?? '';
 74→  const [repostCaption, setRepostCaption] = useState('');
 75→  const [showRepost, setShowRepost] = useState(false);
 76→  const scrollViewRef = useRef<ScrollView>(null);
 77→  const inputRef = useRef<TextInput>(null);
 78→
 79→  const onReplyActivated = useCallback(() => {
 80→    setTimeout(() => {
 81→      inputRef.current?.focus();
 82→      scrollViewRef.current?.scrollToEnd({animated: true});
 83→    }, 100);
 84→  }, []);
 85→
 86→  const detailQuery = useQuery({
 87→    queryKey: ['journal', journalId, user?.id],
 88→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
 89→  });
 90→
 91→  const receiverId = (detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id) || undefined;
 92→
 93→  const {
 94→    comments,
 95→    isLoading: commentsLoading,
 96→    commentInput,
 97→    setCommentInput,
 98→    replyingTo,
 99→    setReplyingTo,
100→    expandedReplies,
101→    fetchedReplies,
102→    loadingReplies,
103→    handleReply,
104→    handleToggleReplies,
105→    submitComment,
106→    isSubmitting,
107→  } = useComments(journalId, receiverId, token, onReplyActivated);
108→
109→  const reactionMutation = useMutation({
110→    mutationFn: async (reactionType: string) => {
111→      const journal = detailQuery.data?.journal;
112→      const rid = journal?.user_id ?? journal?.users?.id;
113→      if (!token) throw new Error('Please log in to react.');
114→      if (!journal?.id || !rid) throw new Error('Missing journal data.');
115→      return socialApi.toggleReaction(token, {
116→        journalId: journal.id,
117→        receiverId: rid,
118→        reactionType,
119→      });
120→    },
121→    onSuccess: () => {
122→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
123→      queryClient.invalidateQueries({queryKey: ['feed']});
124→    },
125→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
126→  });
127→
128→  const bookmarkMutation = useMutation({
129→    mutationFn: async () => {
130→      if (!token) throw new Error('Please log in to bookmark.');
131→      return socialApi.toggleBookmark(token, {journalId});
132→    },
133→    onSuccess: () => {
134→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
135→      queryClient.invalidateQueries({queryKey: ['feed']});
136→    },
137→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
138→  });
139→
140→  const repostMutation = useMutation({
141→    mutationFn: async () => {
142→      if (!token) throw new Error('Please log in to repost.');
143→      return socialApi.createRepost(token, {
144→        sourceJournalId: journalId,
145→        caption: repostCaption.trim() || undefined,
146→      });
147→    },
148→    onSuccess: () => {
149→      setRepostCaption('');
150→      setShowRepost(false);
151→      Alert.alert('Reposted', 'Post was reposted to your feed.');
152→      queryClient.invalidateQueries({queryKey: ['feed']});
153→    },
154→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
155→  });
156→
157→  const journal = detailQuery.data?.journal;
158→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
159→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
160→  const bookmarkCount = resolveCount(journal?.bookmark_count);
161→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
162→  const isRepost = !!journal?.is_repost;
163→  const repostSource = isRepost ? journal?.repost_source : null;
164→  const repostSourcePreview = repostSource?.content
165→    ? extractPlainText(repostSource.content).slice(0, 200)
166→    : '';
167→
168→  if (detailQuery.isLoading) {
169→    return (
170→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
171→        <View style={styles.loadingContainer}>
172→          <SkeletonLoader height={200} borderRadius={0} />
173→          <View style={styles.contentPadding}>
174→            <SkeletonLoader width="70%" height={24} />
175→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
176→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
177→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
178→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
179→          </View>
180→        </View>
181→      </SafeAreaView>
182→    );
183→  }
184→
185→  if (detailQuery.isError) {
186→    return (
187→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
188→        <View style={styles.contentPadding}>
189→          <Text style={[styles.errorText, {color: colors.danger}]}>
190→            Unable to load this post.
191→          </Text>
192→        </View>
193→      </SafeAreaView>
194→    );
195→  }
196→
197→  return (
198→    <ScrollView
199→      ref={scrollViewRef}
200→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
201→      showsVerticalScrollIndicator={false}>
202→      {/* Banner image */}
203→      {!isRepost && bannerImage && (
204→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
205→      )}
206→
207→      <View style={styles.contentPadding}>
208→        {/* Title / Repost badge */}
209→        {isRepost ? (
210→          <View style={styles.repostBadge}>
211→            <RepostIcon size={14} color={colors.textFaint} />
212→            <Text style={[styles.repostBadgeText, {color: colors.textFaint}]}>
213→              <Text style={[styles.repostBadgeName, {color: colors.textSecondary}]}>
214→                {journal?.users?.name || 'Someone'}
215→              </Text>
216→              {' reposted'}
217→            </Text>
218→          </View>
219→        ) : (
220→          <Text style={[styles.title, {color: colors.textHeading}]}>
221→            {journal?.title || 'Untitled Post'}
222→          </Text>
223→        )}
224→
225→        {/* Author section */}
226→        <Pressable
227→          style={styles.authorRow}
228→          onPress={() => {
229→            const authorId = journal?.users?.id ?? journal?.user_id;
230→            if (!authorId) return;
231→            if (authorId === user?.id) {
232→              navigation.navigate('Main' as any, {screen: 'Profile'});
233→            } else {
234→              navigation.navigate('VisitProfile', {
235→                userId: authorId,
236→                username: journal?.users?.username ?? undefined,
237→              });
238→            }
239→          }}>
240→          <Avatar
241→            uri={journal?.users?.image_url}
242→            name={journal?.users?.name}
243→            size={36}
244→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
245→          />
246→          <View style={styles.authorInfo}>
247→            <View style={styles.authorNameRow}>
248→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
249→                {journal?.users?.name || 'Unknown author'}
250→              </Text>
251→              {journal?.users?.badge ? (
252→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
253→              ) : null}
254→            </View>
255→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
256→              {formatRelativeDate(journal?.created_at)}
257→            </Text>
258→          </View>
259→        </Pressable>
260→
261→        {/* Repost caption */}
262→        {isRepost && journal?.repost_caption ? (
263→          <Text style={[styles.repostCaptionText, {color: colors.textPrimary}]}>
264→            {journal.repost_caption}
265→          </Text>
266→        ) : null}
267→
268→        {/* Action bar */}
269→        <ActionBar
270→          likeCount={likeCount}
271→          commentCount={commentCount}
272→          bookmarkCount={bookmarkCount}
273→          isLiked={journal?.has_liked}
274→          isBookmarked={journal?.has_bookmarked}
275→          userReaction={journal?.user_reaction}
276→          onReact={type => reactionMutation.mutate(type)}
277→          onComment={() => {/* scroll to comments */}}
278→          onBookmark={() => bookmarkMutation.mutate()}
279→          onRepost={() => setShowRepost(!showRepost)}
280→        />
281→
282→        {/* Repost section */}
283→        {showRepost && (
284→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
285→            <TextInput
286→              value={repostCaption}
287→              onChangeText={setRepostCaption}
288→              placeholder="Add an optional caption"
289→              placeholderTextColor={colors.textFaint}
290→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
291→              maxLength={280}
292→              multiline
293→            />
294→            <PrimaryButton
295→              label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
296→              onPress={() => repostMutation.mutate()}
297→              disabled={repostMutation.isPending}
298→            />
299→          </View>
300→        )}
301→
302→        {/* Divider */}
303→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
304→
305→        {/* Content body / Embedded original post */}
306→        {isRepost ? (
307→          repostSource ? (
308→            <Pressable
309→              style={[styles.embeddedCard, {borderColor: colors.borderLight}]}
310→              onPress={() => navigation.push('PostDetail', {journalId: repostSource.id})}>
311→              <View style={styles.embeddedAuthorRow}>
312→                <Avatar
313→                  uri={repostSource.users?.image_url ?? undefined}
314→                  name={repostSource.users?.name ?? undefined}
315→                  size={28}
316→                  badge={repostSource.users?.badge as 'legend' | 'og' | undefined}
317→                />
318→                <Text style={[styles.embeddedAuthorName, {color: colors.textPrimary}]}>
319→                  {repostSource.users?.name || 'Unknown author'}
320→                </Text>
321→              </View>
322→              {repostSource.title ? (
323→                <Text style={[styles.embeddedTitle, {color: colors.textHeading}]}>
324→                  {repostSource.title}
325→                </Text>
326→              ) : null}
327→              {repostSourcePreview ? (
328→                <Text style={[styles.embeddedPreview, {color: colors.textSecondary}]} numberOfLines={3}>
329→                  {repostSourcePreview}
330→                </Text>
331→              ) : null}
332→            </Pressable>
333→          ) : (
334→            <View style={[styles.embeddedCard, {borderColor: colors.borderLight}]}>
335→              <Text style={[styles.repostUnavailable, {color: colors.textMuted}]}>
336→                This post is no longer available
337→              </Text>
338→            </View>
339→          )
340→        ) : (
341→          <>
342→            <LexicalRenderer content={journal?.content} />
343→            <RelatedPosts journalId={journalId} />
344→          </>
345→        )}
346→
347→        {/* Divider */}
348→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
349→
350→        {/* Comments section */}
351→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
352→          Comments ({commentCount})
353→        </Text>
354→
355→        {commentsLoading ? (
356→          <View style={styles.commentLoading}>
357→            <ActivityIndicator color={colors.loaderColor} />
358→          </View>
359→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
360→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
361→            No comments yet. Be the first!
362→          </Text>
363→        ) : (
364→          comments
365→            .filter(c => !c.parent_id)
366→            .map(comment => (
367→              <CommentThread
368→                key={comment.id}
369→                comment={comment}
370→                postId={journalId}
371→                allComments={comments}
372→                fetchedReplies={fetchedReplies}
373→                loadingReplies={loadingReplies}
374→                isLoggedIn={!!token}
375→                onReply={handleReply}
376→                onToggleReplies={handleToggleReplies}
377→                expandedReplies={expandedReplies}
378→                colors={colors}
379→                depth={0}
380→              />
381→            ))
382→        )}
383→
384→        {/* Comment input */}
385→        {token ? (
386→          <View style={styles.commentInputRow}>
387→            {replyingTo && (
388→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
389→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
390→                  Replying to {replyingTo.userName}
391→                </Text>
392→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
393→                  <XIcon size={16} color={colors.textMuted} />
394→                </Pressable>
395→              </View>
396→            )}
397→            <TextInput
398→              ref={inputRef}
399→              value={commentInput}
400→              onChangeText={setCommentInput}
401→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
402→              placeholderTextColor={colors.textFaint}
403→              style={[
404→                styles.commentInput,
405→                {
406→                  backgroundColor: colors.bgSecondary,
407→                  borderColor: colors.borderCard,
408→                  color: colors.textPrimary,
409→                },
410→              ]}
411→              maxLength={200}
412→              multiline
413→            />
414→            <PrimaryButton
415→              label={isSubmitting ? 'Posting...' : 'Post'}
416→              onPress={submitComment}
417→              disabled={commentInput.trim().length === 0 || isSubmitting}
418→            />
419→          </View>
420→        ) : null}
421→
422→        <View style={styles.bottomSpacer} />
423→      </View>
424→    </ScrollView>
425→  );
426→}
427→
