292→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
293→    const formData = new FormData();
294→
295→    const lexicalPayload = {
296→      root: {
297→        children: [
298→          {
299→            type: 'paragraph',
300→            children: [
301→              {
302→                type: 'text',
303→                text: payload.plainText,
304→                detail: 0,
305→                format: 0,
306→                mode: 'normal',
307→                style: '',
308→                version: 1,
309→              },
310→            ],
311→            direction: null,
312→            format: '',
313→            indent: 0,
314→            version: 1,
315→          },
316→        ],
317→        direction: null,
318→        format: '',
319→        indent: 0,
320→        type: 'root',
321→        version: 1,
322→      },
323→    };
324→
325→    formData.append('title', payload.title);
326→    formData.append('content', JSON.stringify(lexicalPayload));
327→    formData.append('post_type', 'text');
328→
329→    return apiRequest<{ message?: string }>('/save-journal', {
330→      method: 'POST',
331→      headers: {
332→        ...authHeaders(token),
333→      },
334→      body: formData,
335→      timeoutMs: 30000,
336→      retries: 0,
337→    });
338→  },
