266→        </Pressable>
267→
268→        {/* Repost caption */}
269→        {isRepost && journal?.repost_caption ? (
270→          <Text style={[styles.repostCaptionText, {color: colors.textPrimary}]}>
271→            {journal.repost_caption}
272→          </Text>
273→        ) : null}
274→
275→        {/* Action bar */}
276→        <ActionBar
277→          likeCount={likeCount}
278→          commentCount={commentCount}
279→          bookmarkCount={bookmarkCount}
280→          isLiked={journal?.has_liked}
281→          isBookmarked={journal?.has_bookmarked}
282→          userReaction={journal?.user_reaction}
283→          onReact={type => reactionMutation.mutate(type)}
284→          onComment={() => {/* scroll to comments */}}
285→          onBookmark={() => bookmarkMutation.mutate()}
286→          onRepost={() => setShowRepost(!showRepost)}
287→        />
288→
289→        {/* Repost section */}
290→        {showRepost && (
291→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
292→            <TextInput
293→              value={repostCaption}
294→              onChangeText={setRepostCaption}
295→              placeholder="Add an optional caption"
296→              placeholderTextColor={colors.textFaint}
297→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
298→              maxLength={280}
299→              multiline
300→            />
301→            <PrimaryButton
302→              label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
303→              onPress={() => repostMutation.mutate()}
304→              disabled={repostMutation.isPending}
305→            />
306→          </View>
307→        )}
308→
309→        {/* Divider */}
310→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
311→
312→        {/* Content body / Embedded original post */}
313→        {isRepost ? (
314→          repostSource ? (
315→            <Pressable
316→              style={[styles.embeddedCard, {borderColor: colors.borderLight}]}
317→              onPress={() => navigation.push('PostDetail', {journalId: repostSource.id})}>
318→              <View style={styles.embeddedAuthorRow}>
319→                <Avatar
320→                  uri={repostSource.users?.image_url ?? undefined}
321→                  name={repostSource.users?.name ?? undefined}
322→                  size={28}
323→                  badge={repostSource.users?.badge as 'legend' | 'og' | undefined}
324→                />
325→                <Text style={[styles.embeddedAuthorName, {color: colors.textPrimary}]}>
326→                  {repostSource.users?.name || 'Unknown author'}
327→                </Text>
328→              </View>
329→              {repostSource.title ? (
330→                <Text style={[styles.embeddedTitle, {color: colors.textHeading}]}>
331→                  {repostSource.title}
332→                </Text>
333→              ) : null}
334→              {repostSourcePreview ? (
335→                <Text style={[styles.embeddedPreview, {color: colors.textSecondary}]} numberOfLines={3}>
336→                  {repostSourcePreview}
337→                </Text>
338→              ) : null}
339→            </Pressable>
340→          ) : (
341→            <View style={[styles.embeddedCard, {borderColor: colors.borderLight}]}>
342→              <Text style={[styles.repostUnavailable, {color: colors.textMuted}]}>
343→                This post is no longer available
344→              </Text>
345→            </View>
346→          )
347→        ) : (
348→          <>
349→            {isCanvas && !journal?.content ? null : <LexicalRenderer content={journal?.content} />}
350→            <RelatedPosts journalId={journalId} />
351→          </>
352→        )}
353→
354→        {/* Divider */}
355→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
356→
357→        {/* Comments section */}
358→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
359→          Comments ({commentCount})
360→        </Text>
361→
362→        {commentsLoading ? (
363→          <View style={styles.commentLoading}>
364→            <ActivityIndicator color={colors.loaderColor} />
365→          </View>
366→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
367→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
368→            No comments yet. Be the first!
369→          </Text>
370→        ) : (
371→          comments
372→            .filter(c => !c.parent_id)
373→            .map(comment => (
374→              <CommentThread
375→                key={comment.id}
376→                comment={comment}
377→                postId={journalId}
378→                allComments={comments}
379→                fetchedReplies={fetchedReplies}
380→                loadingReplies={loadingReplies}
381→                isLoggedIn={!!token}
382→                onReply={handleReply}
383→                onToggleReplies={handleToggleReplies}
384→                expandedReplies={expandedReplies}
385→                colors={colors}
386→                depth={0}
387→              />
388→            ))
389→        )}
390→
391→        {/* Comment input */}
392→        {token ? (
393→          <View style={styles.commentInputRow}>
394→            {replyingTo && (
395→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
396→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
397→                  Replying to {replyingTo.userName}
398→                </Text>
399→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
400→                  <XIcon size={16} color={colors.textMuted} />
401→                </Pressable>
402→              </View>
403→            )}
404→            <TextInput
405→              ref={inputRef}
406→              value={commentInput}
407→              onChangeText={setCommentInput}
408→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
409→              placeholderTextColor={colors.textFaint}
410→              style={[
411→                styles.commentInput,
412→                {
413→                  backgroundColor: colors.bgSecondary,
414→                  borderColor: colors.borderCard,
415→                  color: colors.textPrimary,
416→                },
417→              ]}
418→              maxLength={200}
419→              multiline
420→            />
421→            <PrimaryButton
422→              label={isSubmitting ? 'Posting...' : 'Post'}
423→              onPress={submitComment}
424→              disabled={commentInput.trim().length === 0 || isSubmitting}
425→            />
426→          </View>
427→        ) : null}
428→
429→        <View style={styles.bottomSpacer} />
430→      </View>
431→    </ScrollView>
432→  );
433→}
