  3→export const extractPlainText = (rawContent: string | null | undefined): string => {
  4→  if (!rawContent) return '';
  5→  try {
  6→    const parsed = JSON.parse(rawContent) as {
  7→      root?: {children?: Array<{children?: Array<{text?: string}>}>};
  8→    };
  9→    const parts: string[] = [];
 10→    parsed.root?.children?.forEach(node => {
 11→      node.children?.forEach(child => {
 12→        if (child.text) parts.push(child.text);
 13→      });
 14→    });
 15→    return parts.join(' ').replace(/\s+/g, ' ').trim();
 16→  } catch {
 17→    return rawContent.replace(/\s+/g, ' ').trim();
 18→  }
 19→};
 20→
 21→export const extractBannerImage = (
 22→  rawContent: string | null | undefined,
 23→  images?: string | string[] | null,
 24→): string | null => {
 25→  if (images) {
 26→    if (typeof images === 'string') {
 27→      try {
 28→        const parsed = JSON.parse(images);
 29→        if (Array.isArray(parsed) && parsed.length > 0) return parsed[0];
 30→      } catch {
 31→        if (images.startsWith('http')) return images;
 32→      }
 33→    }
 34→    if (Array.isArray(images) && images.length > 0) return images[0];
 35→  }
 36→  if (!rawContent) return null;
 37→  try {
 38→    const parsed = JSON.parse(rawContent);
 39→    const findImage = (node: any): string | null => {
 40→      if (node.type === 'image' && node.src) return node.src;
 41→      if (node.children) {
 42→        for (const child of node.children) {
 43→          const found = findImage(child);
 44→          if (found) return found;
 45→        }
 46→      }
 47→      return null;
 48→    };
 49→    return findImage(parsed.root ?? parsed);
 50→  } catch {
 51→    return null;
 52→  }
 53→};
 54→
 55→export const parseCanvasDoc = (
 56→  raw: CanvasDoc | string | null | undefined,
 57→): CanvasDoc | null => {
 58→  if (!raw) return null;
 59→  if (typeof raw === 'object') return raw;
 60→  try {
 61→    const parsed = JSON.parse(raw);
 62→    return typeof parsed === 'object' && parsed !== null ? parsed : null;
 63→  } catch {
 64→    return null;
 65→  }
 66→};
 67→
 68→export const getCanvasPlainText = (
 69→  raw: CanvasDoc | string | null | undefined,
 70→): string => {
 71→  const doc = parseCanvasDoc(raw);
 72→  if (!doc?.snippets?.length) return '';
 73→  return doc.snippets
 74→    .map(s => s.text)
 75→    .filter(Boolean)
 76→    .join(' ')
 77→    .replace(/\s+/g, ' ')
 78→    .trim();
 79→};
 80→
 81→export const normalizeCount = (value: unknown): number => {
 82→  const parsed = Number(value);
 83→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
 84→};
 85→
 86→export const resolveCount = (
 87→  aggregate: Array<{count?: number}> | undefined,
 88→  fallback?: number,
 89→): number => {
 90→  if (Array.isArray(aggregate) && aggregate.length > 0)
 91→    return normalizeCount(aggregate[0]?.count);
 92→  return normalizeCount(fallback);
 93→};
 94→
 95→export const getNextCursor = (
 96→  page: CursorPage<JournalItem>,
 97→  pageSize: number,
 98→): string | undefined => {
 99→  if (page.nextCursor) return page.nextCursor;
100→  if (page.hasMore && page.data.length > 0)
101→    return page.data[page.data.length - 1]?.created_at ?? undefined;
102→  if (page.data.length >= pageSize)
103→    return page.data[page.data.length - 1]?.created_at ?? undefined;
104→  return undefined;
105→};
