import { apiRequest } from './apiClient';

export type UserPreview = {
  id: string;
  name: string | null;
  username?: string | null;
  image_url?: string | null;
  badge?: string | null;
};

export type CanvasDocMeta = {
  aspectRatio?: '1:1' | '4:5';
  gridEnabled?: boolean;
  theme?: 'light' | 'dark';
};

export type CanvasSnippet = {
  id: string;
  text: string;
  x: number;
  y: number;
  rotation?: number;
  zIndex?: number;
  fontStyle?: string;
  scaleX?: number;
  sizeScale?: number;
};

export type CanvasImage = {
  id: string;
  src: string;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation?: number;
  zIndex?: number;
  scaleX?: number;
};

export type CanvasDoodle = {
  id: string;
  points: number[];
  color?: string;
  size?: number;
};

export type CanvasDoc = {
  meta?: CanvasDocMeta;
  snippets?: CanvasSnippet[];
  images?: CanvasImage[];
  doodles?: CanvasDoodle[];
};

export type JournalItem = {
  id: string;
  title: string | null;
  content: string | null;
  canvas_doc?: CanvasDoc | string | null;
  post_type?: string | null;
  user_id?: string | null;
  privacy?: string | null;
  created_at?: string;
  likes_count?: number;
  comments_count?: number;
  has_liked?: boolean;
  has_bookmarked?: boolean;
  user_reaction?: string | null;
  reaction_count?: Array<{count?: number}>;
  like_count?: Array<{count?: number}>;
  comment_count?: Array<{count?: number}>;
  bookmark_count?: Array<{count?: number}>;
  is_repost?: boolean;
  repost_caption?: string | null;
  repost_source?: JournalItem | null;
  users?: UserPreview | null;
};

export type CursorPage<T> = {
  data: T[];
  nextCursor?: string | null;
  hasMore?: boolean;
};

export type NotificationItem = {
  id: string;
  sender_id?: string;
  receiver_id?: string;
  journal_id?: string;
  repost_journal_id?: string | null;
  opinion_id?: string | null;
  type?: string;
  source?: 'journal' | 'opinion' | string;
  users?: UserPreview | null;
  journals?: JournalItem | null;
  opinions?: {
    id?: string;
    opinion?: string;
    user_id?: string;
    created_at?: string;
  } | null;
  message?: string;
  created_at?: string;
  read?: boolean;
};

type UniversePost = {
  id: string;
  title?: string | null;
  x?: number;
  y?: number;
};

export type StreakResponse = {
  currentStreak?: number;

